const promise = new Promise((resolve, reject) => {
  // The executor runs synchronously, immediately:
  const success = Math.random() > 0.5;

  if (success) {
    resolve('Operation succeeded!'); // fulfills the Promise
  } else {
    reject(new Error('Operation failed')); // rejects the Promise
  }
});

// In practice you rarely construct Promises manually — APIs like fetch()
// already return Promises. You write new Promise() mainly when wrapping
// older callback-based APIs:

// Wrapping setTimeout in a Promise:
function delay(ms) {
  return new Promise(resolve => setTimeout(resolve, ms));
}

// Wrapping a callback-based Node.js readFile:
import { readFile } from 'fs';

function readFilePromise(path) {
  return new Promise((resolve, reject) => {
    readFile(path, 'utf8', (err, data) => {
      if (err) reject(err);
      else resolve(data);
    });
  });
}

fetch('https://api.example.com/users/1')
  .then(response => {
    // Called when the Promise fulfills.
    // The return value becomes the input to the next .then().
    if (!response.ok) throw new Error(`HTTP error: ${response.status}`);
    return response.json(); // also returns a Promise
  })
  .then(user => {
    // Receives the resolved value of response.json()
    console.log(user.name);
  })
  .catch(error => {
    // Called when ANY .then() above throws or when the original Promise rejects.
    console.error('Failed:', error.message);
  })
  .finally(() => {
    // Always called — whether fulfilled or rejected.
    // Good for cleanup: hide loading spinner, release locks, etc.
    setLoading(false);
  });

function fetchUser(id) {
  return fetch(`/api/users/${id}`).then(r => r.json());
}

function fetchPostsByUser(userId) {
  return fetch(`/api/posts?userId=${userId}`).then(r => r.json());
}

// Chain: fetch user, then fetch that user's posts
fetchUser(1)
  .then(user => {
    console.log('User:', user.name);
    return fetchPostsByUser(user.id); // returns a Promise — chain waits
  })
  .then(posts => {
    // posts is the resolved value of fetchPostsByUser
    console.log('Posts:', posts.length);
  })
  .catch(err => console.error(err));

// Resolves when ALL promises resolve; rejects as soon as ANY rejects.
// Result is an array of resolved values in the same order as input.
const [user, posts, comments] = await Promise.all([
  fetch('/api/users/1').then(r => r.json()),
  fetch('/api/posts').then(r => r.json()),
  fetch('/api/comments').then(r => r.json()),
]);
// If any one fetch fails, the entire Promise.all rejects.

// Waits for ALL promises to settle (fulfill or reject).
// Never rejects — result is an array of outcome objects.
const results = await Promise.allSettled([
  fetch('/api/users').then(r => r.json()),
  fetch('/api/broken-endpoint').then(r => r.json()),
]);

results.forEach(result => {
  if (result.status === 'fulfilled') {
    console.log('Got:', result.value);
  } else {
    console.error('Failed:', result.reason.message);
  }
});
// Use when you want to run all requests even if some fail.

// Resolves or rejects with the first promise to settle — fulfilled or rejected.
const result = await Promise.race([
  fetch('/api/data'),
  new Promise((_, reject) =>
    setTimeout(() => reject(new Error('Request timed out')), 5000)
  ),
]);
// Classic use case: adding a timeout to a fetch that has no built-in timeout.

// Resolves with the first fulfilled promise; only rejects if ALL reject.
const fastestCDN = await Promise.any([
  fetch('https://cdn1.example.com/data.json'),
  fetch('https://cdn2.example.com/data.json'),
  fetch('https://cdn3.example.com/data.json'),
]);
