import { useState, useEffect } from 'react';

function UserProfile({ userId }) {
  const [user, setUser]     = useState(null);
  const [error, setError]   = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false; // prevents setting state on unmounted component

    setLoading(true);
    setError(null);

    fetch(`/api/users/${userId}`)
      .then(response => {
        if (!response.ok) throw new Error(`HTTP ${response.status}`);
        return response.json();
      })
      .then(data => {
        if (!cancelled) setUser(data);
      })
      .catch(err => {
        if (!cancelled) setError(err.message);
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => {
      cancelled = true; // cleanup: ignore response if userId changed
    };
  }, [userId]);

  if (loading) return <p>Loading...</p>;
  if (error)   return <p>Error: {error}</p>;
  return <h1>{user.name}</h1>;
}

import { useState, useEffect } from 'react';

function Dashboard({ userId }) {
  const [data, setData]     = useState(null);
  const [error, setError]   = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;

    // Fire both requests simultaneously instead of sequentially:
    Promise.all([
      fetch(`/api/users/${userId}`).then(r => r.json()),
      fetch(`/api/users/${userId}/stats`).then(r => r.json()),
    ])
      .then(([user, stats]) => {
        if (!cancelled) setData({ user, stats });
      })
      .catch(err => {
        if (!cancelled) setError(err.message);
      })
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    return () => { cancelled = true; };
  }, [userId]);

  if (loading) return <p>Loading dashboard...</p>;
  if (error)   return <p>Error: {error}</p>;
  return (
    <div>
      <h1>{data.user.name}</h1>
      <p>Posts: {data.stats.postCount}</p>
    </div>
  );
}

// ❌ Missing return — the next .then() gets undefined
fetch('/api/users')
  .then(response => {
    response.json(); // forgot return!
  })
  .then(data => {
    console.log(data); // undefined — not the parsed JSON
  });

// ✅ Always return from .then():
fetch('/api/users')
  .then(response => response.json())
  .then(data => console.log(data));

// ❌ No .catch() — if the fetch fails, the error is swallowed silently
fetch('/api/data')
  .then(r => r.json())
  .then(data => setData(data));

// ✅ Always add .catch() at the end of a chain
fetch('/api/data')
  .then(r => r.json())
  .then(data => setData(data))
  .catch(err => setError(err.message));

// ❌ If the component unmounts before fetch completes, setData is called
// on an unmounted component — React shows a warning (React < 18) and
// potentially causes subtle bugs in React 18+.
useEffect(() => {
  fetch('/api/data')
    .then(r => r.json())
    .then(data => setData(data)); // might run after unmount
}, []);

// ✅ Use the cancelled flag pattern (shown above) or an AbortController:
useEffect(() => {
  const controller = new AbortController();
  fetch('/api/data', { signal: controller.signal })
    .then(r => r.json())
    .then(data => setData(data))
    .catch(err => {
      if (err.name !== 'AbortError') setError(err.message);
    });
  return () => controller.abort();
}, []);

// ❌ fetch() only rejects on network failure — a 404 or 500 still fulfills
fetch('/api/nonexistent')
  .then(r => r.json()) // succeeds even with a 404 response
  .then(data => console.log(data)) // data might be an error object
  .catch(err => console.error(err)); // only fires for network errors

// ✅ Always check response.ok:
fetch('/api/nonexistent')
  .then(r => {
    if (!r.ok) throw new Error(`HTTP error: ${r.status}`);
    return r.json();
  })
  .then(data => console.log(data))
  .catch(err => console.error(err)); // now catches both network and HTTP errors

// .then() chain version:
useEffect(() => {
  let cancelled = false;
  fetch(`/api/users/${userId}`)
    .then(r => r.json())
    .then(data => { if (!cancelled) setUser(data); })
    .catch(err => { if (!cancelled) setError(err.message); });
  return () => { cancelled = true; };
}, [userId]);

// async/await version — identical behaviour, different syntax:
useEffect(() => {
  let cancelled = false;
  async function load() {
    try {
      const r    = await fetch(`/api/users/${userId}`);
      const data = await r.json();
      if (!cancelled) setUser(data);
    } catch (err) {
      if (!cancelled) setError(err.message);
    }
  }
  load();
  return () => { cancelled = true; };
}, [userId]);

import { describe, it, expect, vi } from 'vitest';

// Function under test:
function fetchUser(id) {
  return fetch(`/api/users/${id}`)
    .then(r => {
      if (!r.ok) throw new Error(`HTTP ${r.status}`);
      return r.json();
    });
}

describe('fetchUser', () => {
  it('returns user data on success', () => {
    // Mock fetch so the test never hits the network:
    vi.stubGlobal('fetch', vi.fn().mockResolvedValue({
      ok: true,
      json: () => Promise.resolve({ id: 1, name: 'Alice' }),
    }));

    // Return the Promise — Vitest waits for it:
    return fetchUser(1).then(user => {
      expect(user.name).toBe('Alice');
    });
  });

  it('throws on HTTP error', () => {
    vi.stubGlobal('fetch', vi.fn().mockResolvedValue({
      ok: false,
      status: 404,
    }));

    // Return the rejected Promise and assert on the error:
    return fetchUser(99).catch(err => {
      expect(err.message).toBe('HTTP 404');
    });
  });
});

it('returns user data on success', async () => {
  vi.stubGlobal('fetch', vi.fn().mockResolvedValue({
    ok: true,
    json: () => Promise.resolve({ id: 1, name: 'Alice' }),
  }));
  const user = await fetchUser(1);
  expect(user.name).toBe('Alice');
});

it('throws on HTTP error', async () => {
  vi.stubGlobal('fetch', vi.fn().mockResolvedValue({ ok: false, status: 404 }));
  await expect(fetchUser(99)).rejects.toThrow('HTTP 404');
  // .rejects.toThrow() is the cleaner API — no manual .catch() needed
});

// Promise.resolve(value) — creates an immediately-fulfilled Promise:
Promise.resolve(42).then(v => console.log(v)); // 42

// Promise.reject(reason) — creates an immediately-rejected Promise:
Promise.reject(new Error('oops')).catch(e => console.error(e.message)); // 'oops'

// Useful in tests to mock async functions:
const mockFetch = vi.fn().mockReturnValue(
  Promise.resolve({ ok: true, json: () => Promise.resolve({ name: 'Test' }) })
);

// Useful to normalise sync/async return values:
function getConfig(overrides) {
  if (overrides) return Promise.resolve({ ...defaultConfig, ...overrides });
  return fetch('/api/config').then(r => r.json());
}
